// GENERATED by tools/bundle.mjs from examples/field-guide/harness.config.mjs — do not hand-edit; edit the config and rebundle.
// Engine: engine/dual_agent_loop.mjs · Contract: SEAT_CONTRACT.md · Constitution: TRUSTS.md

// dual_agent_loop.mjs — the soulbis ⚔️ ⊥ soulbae 🧙 dual-agent harness engine.
//
//   (⚔️⊥⿻⊥🧙)😊 = neg ⊕ bnot → succ
//
// Target-agnostic. A concrete harness is a CONFIG (see SEAT_CONTRACT.md)
// passed to runHarness(config, rt). The two invariants the loop exists to
// keep: I(Y_S; Y_M | X) = 0 (the proposer never touches the held-out
// witnesses) and I(S; M | FP) < ε (the pair share only their root in the
// First Person). See TRUSTS.md.
//
// rt = { agent, parallel, pipeline, phase, log } — the Claude Code Workflow
// globals, or your own driver. No imports here: tools/bundle.mjs concatenates
// this file with a config into one self-contained .workflow.mjs.

function bootPreamble(root, repo, seatCard) {
  return `You are a seat in a soulbis/soulbae dual-agent harness. Instance: ${repo}. Skeleton root: ${root}.
BOOT (mandatory, in order): read ${root}/GROUND_RULES.md, then ${root}/TRUSTS.md, then your seat card ${root}/seats/${seatCard}, then ${repo}/frontier.json. If any of these files is missing, STOP and return an error naming the missing path — do not proceed unbound (T3). GR-1..GR-10 and trusts T1..T6 bind you. Read nothing else shared between seats (T3). Your final message is consumed as data by the orchestrator, not shown to a human.`
}

function validateConfig(config) {
  const errs = []
  const need = (cond, msg) => { if (!cond) errs.push(msg) }
  need(config && typeof config.name === 'string' && config.name, 'config.name required')
  need(config?.door === 'first-person', "config.door must be the literal 'first-person' (T6: the door is the First Person's)")
  need(typeof config?.heldApartRule === 'string' && config.heldApartRule.trim().length > 0, 'config.heldApartRule required (T2/GR-4: the Gap is held apart)')
  need(config?.objective?.metric, 'config.objective.metric required (GR-1)')
  need(config?.objective?.gate, 'config.objective.gate required (T5: the multiplicative gate)')
  need(config?.objective?.hardConstraint, 'config.objective.hardConstraint required (GR-3)')
  need(Array.isArray(config?.keystoneOnlyWrites) && config.keystoneOnlyWrites.length > 0, 'config.keystoneOnlyWrites required (GR-10)')
  need(Array.isArray(config?.finders) && config.finders.length >= 2, 'config.finders needs >= 2 lenses (blind complements)')
  if (Array.isArray(config?.finders)) {
    const lenses = new Set(config.finders.map(f => f && f.lens))
    need(lenses.size === config.finders.length, 'config.finders lenses must be distinct')
  }
  for (const p of ['measure', 'propose', 'holdApart', 'assay', 'critic', 'chronicle']) {
    need(typeof config?.prompts?.[p] === 'function', `config.prompts.${p} required (T1: the promises must be seated)`)
  }
  for (const s of ['measure', 'proposal', 'gap', 'verdict', 'critic']) {
    need(config?.schemas?.[s] && typeof config.schemas[s] === 'object', `config.schemas.${s} required`)
  }
  need(typeof config?.isValidated === 'function', 'config.isValidated required')
  need(typeof config?.isStructural === 'function', 'config.isStructural required')
  need(Number.isFinite(config?.stop?.dryRounds) && config.stop.dryRounds >= 1, 'config.stop.dryRounds required')
  need(Number.isFinite(config?.stop?.maxRounds) && config.stop.maxRounds >= 1, 'config.stop.maxRounds required')
  return errs
}

async function runHarness(config, rt, runArgs = {}) {
  const { agent, parallel, pipeline, phase, log } = rt
  const errs = validateConfig(config)
  if (errs.length) throw new Error('config violates the seat contract:\n  - ' + errs.join('\n  - '))

  const repo = String(runArgs.repo || config.repo || '').replace(/\\/g, '/')
  if (!repo) throw new Error('runArgs.repo required (absolute path to the harness instance)')
  // root = where GROUND_RULES.md, TRUSTS.md, and seats/ live (the skeleton
  // clone). Defaults to the instance itself, which is only correct if the
  // instance carries its own copies (T3: every seat boots from the same docs).
  const root = String(runArgs.root || config.root || repo).replace(/\\/g, '/')
  const runId = String(runArgs.runId || 'r0')
  const runDir = `${repo}/runs/${runId}`
  // ctx.args exposes the run's arguments to prompt builders, so a config can
  // scope a run (one section, one module, one file) instead of turning every
  // round loose on the whole target. Scope is declared by the CONFIG and the
  // First Person — never by the proposer (T2).
  const ctx = { root, repo, runId, runDir, config, args: runArgs }
  const BOOT = (card) => bootPreamble(root, repo, card)

  // Per-seat model/effort. A measure that counts words and a Gap that must
  // hash and draw are not the same job; paying frontier prices for both is how
  // a round dies of its own weight. Defaults to the caller's model.
  const seatOpts = (seat) => (config.seatOpts && config.seatOpts[seat]) || {}

  const rounds = []
  const tally = { VALIDATED: 0, MIRAGE: 0, BLOCKED: 0 }
  let confirmed = []
  let dry = 0
  let round = 0
  let aborted = null   // set when a round dies of infrastructure, not of ideas

  while (dry < config.stop.dryRounds && round < config.stop.maxRounds) {
    round += 1
    const roundId = `${runId}.${round}`

    // ---- Measure — numbers only, no advocacy ----
    phase('Measure')
    log(`round ${roundId} opens — measure syncs the frontier`)
    const measure = await agent(`${BOOT('measure.md')}\n${config.prompts.measure(ctx)}`,
      { label: `measure:${roundId}`, phase: 'Measure', schema: config.schemas.measure, ...seatOpts('measure') })

    // ---- Propose — soulbae 🧙, parallel lenses, blind to each other ----
    phase('Propose')
    const proposalSets = await parallel(config.finders.map(f => () => agent(
      `${BOOT('soulbae-propose.md')}\nHELD-APART RULE (T2/GR-4, binding): ${config.heldApartRule}\n${config.prompts.propose(f, measure, ctx)}`,
      { label: `propose:${f.lens}`, phase: 'Propose', schema: config.schemas.proposal, ...seatOpts('propose') })))
    const proposals = proposalSets.filter(Boolean).flatMap(s => s.proposals || [])
    log(`${proposals.length} proposal(s) on the table: ${proposals.map(p => p.leverId).join(', ') || 'none'}`)

    let closed = []
    let critic = null
    if (proposals.length > 0) {
      // ---- per proposal: Hold-apart (the Gap ⿻) then Assay (soulbis ⚔️), no barrier ----
      closed = (await pipeline(
        proposals,
        (p, _item, i) => agent(
          `${BOOT('gap-hold-apart.md')}\n${config.prompts.holdApart(p, i, ctx)}`,
          { label: `gap:${p.leverId}`, phase: 'Hold-apart', schema: config.schemas.gap, ...seatOpts('holdApart') }),
        (gap, p, i) => gap ? agent(
          `${BOOT('soulbis-assay.md')}\n${config.prompts.assay(p, gap, i, ctx)}`,
          { label: `assay:${p.leverId}`, phase: 'Assay', schema: config.schemas.verdict, ...seatOpts('assay') }) : null,
      )).filter(Boolean)
      for (const v of closed) tally[v.status] = (tally[v.status] || 0) + 1
      log(`assay closed: ${closed.length}/${proposals.length} — ${JSON.stringify(tally)}`)

      // ---- Critic — the only barrier: classifies the WHOLE round ----
      phase('Critic')
      critic = await agent(
        `${BOOT('critic.md')}\n${config.prompts.critic(proposals, closed, ctx)}`,
        { label: `critic:${roundId}`, phase: 'Critic', schema: config.schemas.critic, ...seatOpts('critic') })
    }

    // ---- Chronicle — draft only; the keystone reviews and files ----
    phase('Chronicle')
    const roundData = { roundId, measure, proposals, verdicts: closed, critic }
    const chronicle = await agent(
      `${BOOT('chronicle.md')}\n${config.prompts.chronicle(roundData, ctx)}`,
      { label: `chronicle:${roundId}`, phase: 'Chronicle', ...seatOpts('chronicle') })

    // ---- failure accounting (GR-5): a seat that DIED is not a seat that
    // found nothing. A round that lost agents to infrastructure carries no
    // evidence either way, and must never be counted as a dry round —
    // otherwise stop.dryRounds silently converts an outage into "the search
    // is exhausted", and the run reports a clean stop over a pile of corpses.
    const failures = []
    if (measure == null) failures.push('measure')
    const deadFinders = proposalSets.filter(s => s == null).length
    if (deadFinders) failures.push(`propose×${deadFinders}/${config.finders.length}`)
    if (proposals.length > 0) {
      const deadClosings = proposals.length - closed.length
      if (deadClosings) failures.push(`hold-apart|assay×${deadClosings}/${proposals.length}`)
      if (critic == null) failures.push('critic')
    }
    if (chronicle == null) failures.push('chronicle')

    // ---- dry-round accounting: only validated AND structural resets ----
    const validated = closed.filter(v => config.isValidated(v, measure))
    const structural = critic ? validated.filter(v => config.isStructural(critic, v.leverId)) : []

    if (failures.length > 0) {
      aborted = { roundId, failures }
      rounds.push({ ...roundData, roundStatus: 'FAILED', failures, chronicleDraft: chronicle ? String(chronicle).slice(0, 600) : null, validated: [] })
      log(`ROUND ${roundId} FAILED — dead seats: ${failures.join(', ')}. NOT counted as a dry round. Stopping: an incomplete round proves nothing (GR-5).`)
      break
    }

    if (structural.length > 0) { dry = 0; confirmed = confirmed.concat(structural) } else { dry += 1 }
    rounds.push({ ...roundData, roundStatus: 'COMPLETE', chronicleDraft: String(chronicle).slice(0, 600), validated: validated.map(v => v.leverId) })
    log(`round ${roundId} closes — ${structural.length} structural win(s), dry=${dry}/${config.stop.dryRounds}`)
  }

  const status = aborted ? 'INCOMPLETE' : 'COMPLETE'
  return {
    name: config.name, runId, status, rounds: rounds.length, tally, confirmed,
    best: confirmed.length ? confirmed[confirmed.length - 1] : null,
    detail: rounds,
    ...(aborted ? { aborted } : {}),
    keystoneTodo: aborted
      ? `RUN INCOMPLETE — round ${aborted.roundId} lost seats to infrastructure (${aborted.failures.join(', ')}), not to exhausted ideas. FOLD NOTHING: no gate ran on the dead seats, so no verdict here is evidence (GR-5). Re-run the round; the surviving proposals are candidates, not results. Do not move frontier.json.`
      : 'fold VALIDATED levers (frontier.json first, prose second — GR-1); file killedLeverDrafts (GR-6); review + file the chronicle drafts (GR-7); node engine/conform.mjs green before and after (G0); door items listed for the First Person, never opened (G4/T6)',
  }
}

// harness.config.mjs — the field-guide toy instance.
// Objective: minimize the word count of artifact/GUIDE.md while a held-out
// 8-question comprehension gate stays 8/8. See README.md in this directory.

const COUNT_RULE = `tr -s '[:space:]' '\\n' < <file> | grep -c .  (whitespace-split tokens of the full markdown file)`

const config = {
  name: 'field-guide',

  objective: {
    metric: 'words',
    gate: 'held-out comprehension: 8 questions drawn by the Gap from the ORIGINAL guide, answered from the compressed text alone, graded against the original — must be 8/8 (T5: zero collapses)',
    hardConstraint: 'the compressed guide remains a self-contained instruction document: no pointers back to the original, no "see full version", every section still actionable on its own (GR-3)',
  },

  door: 'first-person',

  heldApartRule:
    'You are BLIND to verification witnesses (T2/GR-4). After you finish, the Gap ' +
    'will hash YOUR proposal (including your full compressed text) and use the hash ' +
    'to draw 8 facts from the ORIGINAL guide as comprehension questions. You cannot ' +
    'know which 8 of the ~40 facts will be probed, so the only winning strategy is ' +
    'to preserve ALL semantic content. Do not suggest, guess at, or optimise for ' +
    'any particular questions.',

  keystoneOnlyWrites: ['frontier.json', 'claims_register.md', 'manifest.yaml'],

  finders: [
    { lens: 'line-editor', hint: 'sentence-level compression: cut redundancy, filler, and throat-clearing; convert passive to active; tighten phrasing. NEVER delete a fact — every quantity, duration, temperature, item, and ordered step in the original must survive.' },
    { lens: 'restructurer', hint: 'structure-level compression: merge overlapping sections, convert prose to tables or lists where denser, collapse preamble. NEVER delete a fact — every quantity, duration, temperature, item, and ordered step in the original must survive.' },
  ],

  prompts: {
    measure: (ctx) =>
      `Seat MEASURE. Count the words of ${ctx.repo}/artifact/GUIDE.md mechanically with exactly this rule: ${COUNT_RULE.replace('<file>', ctx.repo + '/artifact/GUIDE.md')}. Compare to frontier.json (baseline and best); flag stale if they disagree. Then price the two lever families (line-editor, restructurer): rough cost to try, rough ceiling in words if fully successful. Numbers only, no advocacy.`,

    propose: (finder, measure, ctx) =>
      `Seat PROPOSE — soulbae 🧙 (bnot), lens = ${finder.lens}: ${finder.hint}
Frontier context: ${JSON.stringify(measure)}.
Read ${ctx.repo}/artifact/GUIDE.md and ${ctx.repo}/notes/KILLED_LEVERS.md (never re-propose a K-id without new cited evidence).
Propose exactly 1 lever through YOUR lens: a complete compressed rewrite of the guide. Your proposal's compressedText field MUST carry the full candidate text (this is the artifact the Gap will hash). State expectedMetric = its word count by the counting rule, and hardConstraintNote = why it is still a self-contained instruction document. Plan and write text only — never touch files.`,

    holdApart: (proposal, i, ctx) =>
      `Seat HOLD-APART — the Gap ⿻ (xor). Proposal artifact (verbatim):
${JSON.stringify(proposal)}
Procedure:
1. Number the ORIGINAL guide's declarative facts: read ${ctx.repo}/artifact/GUIDE.md, split the body into sentences on '.', '!', '?' boundaries in order, and index every sentence that states a checkable fact (quantity, duration, temperature, item, instruction) from F1 upward. Print the full numbered fact list in your transcript.
2. Canonically serialize the proposal artifact above (JSON, recursive sorted keys, no whitespace) and SAVE THOSE EXACT BYTES to ${ctx.runDir}/p${i + 1}-${proposal.leverId}/proposal_canon.json — this file must persist, it is the auditor's only way to re-derive your seed. Then SHA-256 that file with a real shell command; show the exact command and the digest in the transcript. Verify: sha256sum of the saved file must equal seedHex.
3. Draw 8 distinct fact indices without replacement: take the digest bytes left to right as unsigned integers b0,b1,...; for each draw k, idx = b_k mod (number of remaining facts), remove that fact from the remaining list. Show every step.
4. For each drawn fact write one comprehension question with the expected answer quoted from the ORIGINAL sentence.
Write { seedHex, draw, transcript } to ${ctx.runDir}/p${i + 1}-${proposal.leverId}/gap.json (create dirs; draw = the 8 questions + expected answers as JSON text). Leave proposal_canon.json in place — do not clean it up. Never accept witnesses suggested by the proposer.`,

    assay: (proposal, gap, i, ctx) =>
      `Seat ASSAY — soulbis ⚔️ (neg), the prover.
Gap seed=${gap.seedHex}. Re-derive it first, the auditor's way: hash the Gap's saved bytes, \`sha256sum ${ctx.runDir}/p${i + 1}-${proposal.leverId}/proposal_canon.json\`, and confirm it equals seedHex. Verdict BLOCKED if that file is missing or the digest does not reproduce. Transcript: ${gap.transcript}
Then, scratch only (GR-10):
1. Write the proposal's compressedText verbatim to ${ctx.runDir}/p${i + 1}-${proposal.leverId}/candidate.md. The compressed text is:
${JSON.stringify(proposal.compressedText)}
2. Answer the Gap's 8 questions using ONLY candidate.md — do not open the original while answering: ${JSON.stringify(gap.draw)}
3. Grade your 8 answers against the expected answers. gateResult = "n/8". Any wrong or unanswerable question fails the gate.
4. Count candidate.md's words mechanically: ${COUNT_RULE.replace('<file>', ctx.runDir + '/p' + (i + 1) + '-' + proposal.leverId + '/candidate.md')}
5. Check the hard constraint: candidate.md is still a self-contained instruction document.
Verdict VALIDATED only if gateResult is 8/8 AND the hard constraint holds AND words < frontier best (read ${ctx.repo}/frontier.json). A gate fail on a candidate that "reads fine" is a MIRAGE — name the dropped fact. Write the verdict to ${ctx.runDir}/p${i + 1}-${proposal.leverId}/verdict.json too, with EXACTLY the returned shape and no extra nesting: { leverId: string, status: "VALIDATED"|"MIRAGE"|"BLOCKED", metric: number (bare word count), gateResult: "n/8", failingCheck: string (empty if none), evidence: string, scratchDir: string }. The file an auditor reads must match the data the orchestrator receives. Never write frontier.json or claims_register.md.`,

    critic: (proposals, verdicts, ctx) =>
      `Seat CRITIC. Proposals (titles/lenses/expected): ${JSON.stringify(proposals.map(p => ({ leverId: p.leverId, lens: p.lens, title: p.title, expectedMetric: p.expectedMetric })))}
Verdicts: ${JSON.stringify(verdicts)}
Classify each closed lever structural / probe-limited / noise. Red-team the proposer's rationale (did the lens do its job, or did it get lucky/unlucky on the draw?), never the prover's verdict. Draft KILLED_LEVERS entries for structural kills. Name exactly ONE next lead.`,

    chronicle: (round, ctx) =>
      `Seat CHRONICLE. Draft ${ctx.runDir}/CHRONICLE_DRAFT.md following ${ctx.root}/templates/chronicle.md: verdict first, what happened, reversals at win-prominence, ledger entries returned, handoff block ending in the critic's nextLead. Round data: ${JSON.stringify({ roundId: round.roundId, measure: round.measure, proposals: round.proposals.map(p => ({ leverId: p.leverId, lens: p.lens, expectedMetric: p.expectedMetric })), verdicts: round.verdicts, critic: round.critic })}. Return the path plus a 5-line verdict summary.`,
  },

  schemas: {
    measure: {
      type: 'object', required: ['metric', 'stale', 'leverCosts'],
      properties: {
        metric: { type: 'number', description: 'current word count of artifact/GUIDE.md by the counting rule' },
        stale: { type: 'boolean' },
        leverCosts: { type: 'array', items: { type: 'object', required: ['lever', 'cost', 'ceiling'], properties: { lever: { type: 'string' }, cost: { type: 'string' }, ceiling: { type: 'string' } } } },
        notes: { type: 'string' },
      },
    },
    proposal: {
      type: 'object', required: ['proposals'],
      properties: {
        proposals: {
          type: 'array', minItems: 1,
          items: {
            type: 'object',
            required: ['leverId', 'title', 'lens', 'rationale', 'expectedMetric', 'hardConstraintNote', 'compressedText'],
            properties: {
              leverId: { type: 'string', description: 'short kebab id, e.g. cut-filler-pass' },
              title: { type: 'string' },
              lens: { type: 'string', enum: ['line-editor', 'restructurer'] },
              rationale: { type: 'string' },
              expectedMetric: { type: 'number', description: 'word count of compressedText by the counting rule' },
              hardConstraintNote: { type: 'string' },
              compressedText: { type: 'string', description: 'THE FULL compressed guide, verbatim — this is what the Gap hashes' },
              killedLeverCitations: { type: 'array', items: { type: 'string' } },
            },
          },
        },
      },
    },
    gap: {
      type: 'object', required: ['seedHex', 'draw', 'transcript'],
      properties: {
        seedHex: { type: 'string' },
        draw: { type: 'string', description: 'JSON text: the 8 questions with expected answers quoted from the original' },
        transcript: { type: 'string', description: 'numbered fact list + serialization + exact hash command + digest + draw steps, third-party re-derivable' },
      },
    },
    verdict: {
      type: 'object', required: ['leverId', 'status', 'gateResult', 'evidence'],
      properties: {
        leverId: { type: 'string' },
        status: { type: 'string', enum: ['VALIDATED', 'MIRAGE', 'BLOCKED'] },
        metric: { type: 'number', description: 'mechanical word count of candidate.md' },
        gateResult: { type: 'string', description: 'n/8' },
        failingCheck: { type: 'string', description: 'for MIRAGE: the dropped fact / failed question' },
        evidence: { type: 'string' },
        scratchDir: { type: 'string' },
      },
    },
    critic: {
      type: 'object', required: ['classifications', 'nextLead'],
      properties: {
        classifications: { type: 'array', items: { type: 'object', required: ['leverId', 'class', 'why'], properties: { leverId: { type: 'string' }, class: { type: 'string', enum: ['structural', 'probe-limited', 'noise'] }, why: { type: 'string' } } } },
        nextLead: { type: 'string' },
        killedLeverDrafts: { type: 'array', items: { type: 'string' } },
      },
    },
  },

  stop: { dryRounds: 2, maxRounds: 3 },

  isValidated: (v) => v.status === 'VALIDATED' && v.gateResult === '8/8',
  isStructural: (critic, leverId) =>
    (critic.classifications || []).some(c => c.leverId === leverId && c.class === 'structural'),

  conformChecks: [
    (f) => {
      const errs = []
      if (f.objective?.metric !== 'words') errs.push("field-guide frontier objective.metric must be 'words'")
      if (!Number.isFinite(f.baseline?.metric) || f.baseline.metric < 500) errs.push('field-guide baseline should be the measured word count of artifact/GUIDE.md (>= 500)')
      return errs
    },
  ],
}

// ---- run (Workflow globals: agent, parallel, pipeline, phase, log, args) ----
const A = (typeof args === 'string') ? JSON.parse(args) : (args || {})
if (!A.repo) throw new Error('args.repo required (absolute path to this harness instance); args.root = the skeleton clone holding GROUND_RULES.md/TRUSTS.md/seats/, if the instance does not carry its own copies')
return await runHarness(config, { agent, parallel, pipeline, phase, log }, A)
